import { React, useState } from 'react'
import { Container, Grid, Paper, TextField, makeStyles, Button, IconButton, Tooltip, Card, CardContent, MenuItem, Box } from '@material-ui/core'
import StudentActivities from '../components/StudentActivities'
import { AttachFileRounded } from '@material-ui/icons'
import { useLocation } from 'react-router-dom'

const useStyle = makeStyles(theme => {
  return {
    paper: {
      padding: theme.spacing(2)
    },
    input: {
      display: 'none'
    }
  }
})

export default function StudentFeed({ subject }) {

  const classes = useStyle()
  // const location = useLocation()
  // const subject = location.search.slice(1)
  // const subjectSpace = subject.replace("%20", " ")

  const [noPost, setNoPost] = useState(true);


  const [activities, setActivities] = useState([])

  const handlePost = () => {
    alert('Go Bal dito lang ako lagi')
  }


  console.log(subject);

  return (
    <div className={classes.root}>
      <Container maxWidth='sm'>
        <Grid container spacing={3} >

          <Grid item xs={12}>
            <h1>Title</h1>
            <p>BSCpE - 3A</p>
          </Grid>

          <Grid item xs={12}>
            <Paper className={classes.paper} >
              
            <div>
                <form >
              <TextField
                variant='filled'
                color='secondary'
                label='Announcement'
                minRows={4}
                margin='normal'
                fullWidth
                multiline
              />

                  <input className={classes.input} onChange={(e) => console.log(e.target.value)} type="file" accept='image/*' id='attach-file' />
                </form>
                <label htmlFor="attach-file">
                  <IconButton component='span'><Tooltip title='Attach a file' placement='right-start' ><AttachFileRounded /></Tooltip></IconButton>
                </label>
              </div>

              <div>
                <Button variant='contained' color='secondary' size='large' fullWidth disableElevation onClick={handlePost}>Post</Button>
              </div>
            </Paper>
          </Grid>
          {
            noPost ?

              <Paper variant='outlined' fullWidth >
                  <MenuItem disabled>
                    You have no announcement yet.
                  </MenuItem>
              </Paper>

              :

              <Box>
              {activities.map(activity => (
                <Grid item xs={12} key={activity.id}>
                  <StudentActivities activity={activity} />
                </Grid>
              ))}
              </Box>
              
          }


        </Grid>
      </Container>
    </div>
  )
}
